import React, { useEffect, useMemo, useState } from "react";
import Navbar from "../components/Navbar";
import Footer from "../components/Footer";
import FieldCard from "../components/FieldCard";
import { getFields } from "../services/api";

function Fields() {
  const [fields, setFields] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState("");
  const [search, setSearch] = useState("");

  useEffect(() => {
    const fetchFields = async () => {
      try {
        const data = await getFields();
        setFields(data);
      } catch (err) {
        setError(err.message);
      } finally {
        setLoading(false);
      }
    };

    fetchFields();
  }, []);

  const filteredFields = useMemo(() => {
    return fields.filter((field) =>
      field.name?.toLowerCase().includes(search.toLowerCase())
    );
  }, [fields, search]);

  return (
    <div>
      <Navbar />

      <div className="container page-section">
        <div className="section-head">
          <div>
            <h1 className="section-title">Danh sách sân bóng</h1>
            <p className="section-subtitle">
              Tìm kiếm sân phù hợp với nhu cầu và thời gian thi đấu của bạn.
            </p>
          </div>
        </div>

        <div className="filter-bar">
          <input
            type="text"
            placeholder="Tìm theo tên sân..."
            value={search}
            onChange={(e) => setSearch(e.target.value)}
          />
          <button className="btn-primary">Tìm kiếm</button>
        </div>

        {loading && <p>Đang tải dữ liệu...</p>}
        {error && <p className="error-text">{error}</p>}

        {!loading && filteredFields.length === 0 && (
          <div className="empty-box">
            Không tìm thấy sân phù hợp với từ khóa bạn nhập.
          </div>
        )}

        <div className="fields-grid">
          {filteredFields.map((field) => (
            <FieldCard key={field.id} field={field} />
          ))}
        </div>
      </div>

      <Footer />
    </div>
  );
}

export default Fields;
